/**
 * Interfaccia per un singolo allergene
 */
export interface Allergen {
  id: number;
  name: string;
  code: string;
  icon: string; // emoji
}

/**
 * Lista ufficiale dei 14 allergeni obbligatori in UE
 */
export const ALLERGENS: readonly Allergen[] = [
  { id: 1, name: 'Cereali contenenti glutine', code: 'GLUTEN', icon: 'wheat' },
  { id: 2, name: 'Crostacei', code: 'CRUSTACEANS', icon: 'shell' },
  { id: 3, name: 'Uova', code: 'EGGS', icon: 'egg' },
  { id: 4, name: 'Pesce', code: 'FISH', icon: 'fish' },
  { id: 5, name: 'Arachidi', code: 'PEANUTS', icon: 'circle-dot' },
  { id: 6, name: 'Soia', code: 'SOYBEANS', icon: 'sprout' },
  { id: 7, name: 'Latte', code: 'MILK', icon: 'milk' },
  { id: 8, name: 'Frutta a guscio', code: 'NUTS', icon: 'nut' },
  { id: 9, name: 'Sedano', code: 'CELERY', icon: 'leaf' },
  { id: 10, name: 'Senape', code: 'MUSTARD', icon: 'droplet' },
  { id: 11, name: 'Semi di sesamo', code: 'SESAME', icon: 'circle' },
  { id: 12, name: 'Anidride solforosa e solfiti', code: 'SULPHITES', icon: 'wind' },
  { id: 13, name: 'Lupini', code: 'LUPIN', icon: 'flower' },
  { id: 14, name: 'Molluschi', code: 'MOLLUSCS', icon: 'shell' }
] as const;

// Type helper per TypeScript
export type AllergenCode = typeof ALLERGENS[number]['code'];

/**
 * Helper: Ottiene un allergene tramite ID
 */
export function getAllergenById(id: number): Allergen | undefined {
  return ALLERGENS.find(a => a.id === id);
}

/**
 * Helper: Ottiene i nomi degli allergeni da un array di ID
 */
export function getAllergenNames(allergenIds: number[]): string[] {
  return allergenIds
    .map(id => getAllergenById(id)?.name)
    .filter((name): name is string => name !== undefined);
}

// ============================================================
// PROMETHEA - Promotion Model
// Mappa 1:1 con la tabella `promotions` su Supabase
// ============================================================

export type PromotionType =
  | 'percentage'    // Sconto % sul totale o item
  | 'fixed_amount'  // Sconto fisso in €
  | 'happy_hour'    // Fascia oraria automatica
  | 'buy_x_get_y'   // Bundle / 3x2
  | 'free_item';    // Prodotto omaggio

export type DiscountTarget =
  | 'order'         // Intero ordine
  | 'category'      // Categoria prodotti
  | 'product'       // Prodotto specifico
  | 'delivery';     // Solo consegna

export type StackingPolicy =
  | 'exclusive'     // Blocca altri sconti
  | 'cumulative'    // Si somma
  | 'best_deal';    // Vince solo il più vantaggioso

export type PromotionStatus =
  | 'draft'
  | 'active'
  | 'paused'
  | 'expired'
  | 'archived';

export interface Promotion {
  id: string;
  restaurant_id: string;

  // Identità
  name: string;
  description?: string | null;
  internal_note?: string | null;
  image_url?: string | null;

  // Tipo e valore
  type: PromotionType;
  target: DiscountTarget;
  discount_value: number;
  max_discount_amount?: number | null;

  // Validità temporale
  valid_from: string;
  valid_until?: string | null;

  // Limiti di utilizzo
  max_uses_total?: number | null;
  current_uses: number;
  max_uses_per_customer?: number | null;

  // Soglia minima ordine
  min_order_amount: number;

  // Priorità e stacking
  priority: number;
  stacking: StackingPolicy;

  // Stato e visibilità
  status: PromotionStatus;
  is_public: boolean;

  // Metadata
  created_at: string;
  updated_at: string;
  created_by?: string | null;
}

// DTO per la creazione (senza campi auto-generati)
export type CreatePromotionDto = Omit<Promotion,
  'id' | 'restaurant_id' | 'current_uses' | 'created_at' | 'updated_at'
>;

// Statistiche aggregate (da promotion_usages)
export interface PromotionStats {
  promotion_id: string;
  total_uses: number;
  total_discount_given: number;
  avg_order_value: number;
  conversion_rate?: number; // % follower → utilizzo
}

