// PROMOZIONI E MARKETING
export function getDefaultPromotion(): CreatePromotionDto {
  const today = new Date().toISOString().split('T')[0];
  return {
    name: '',
    description: null,
    internal_note: null,
    image_url: null,
    type: 'percentage',
    target: 'order',
    discount_value: 10,
    max_discount_amount: null,
    valid_from: today,
    valid_until: null,
    max_uses_total: null,
    max_uses_per_customer: 1,
    min_order_amount: 0,
    priority: 0,
    stacking: 'exclusive',
    status: 'draft',
    is_public: true,
  };
}

// TASK 
export type TaskStatus     = 'da_iniziare' | 'in_lavorazione' | 'completata';
export type AssociationType = 'interna' | 'cliente';
export type AssignedRole   = 'tutti' | 'manager' | 'chef' | 'waiter' | 'kitchen_staff';

// ─── Entità DB ────────────────────────────────────────────────────────────────

export interface Task {
  id: string;
  restaurant_id: string;
  title: string;
  notes?: string | null;
  priority: number;
  status: TaskStatus;
  association_type: AssociationType;
  client_name?: string | null;
  due_all_day?: boolean;
  assigned_role: AssignedRole | null;
  due_date?: string | null;
  created_at: string;
  updated_at: string;
  is_template?: boolean;        
  template_name?: string | null;
  calendar_event_id?: string | null;   
}

export interface TaskSubtask {
  id: string;
  task_id: string;
  restaurant_id: string;
  name: string;
  priority: number;
  status: TaskStatus;
  due_date?: string | null;
  created_at: string;
  updated_at: string;
}

export interface TaskDetail {
  id: string;
  subtask_id: string;
  restaurant_id: string;
  name: string;
  notes?: string | null;
  due_date?: string | null;
  completed: boolean;
  created_at: string;
  updated_at: string;
}

// ─── View Model (arricchiti con dati calcolati) ───────────────────────────────

export interface TaskDetailView extends TaskDetail {}

export interface TaskSubtaskView extends TaskSubtask {
  details: TaskDetailView[];
  hasDetails: boolean;
  progress: number;        // 0–100, visibile solo se hasDetails
  completedDetails: number;
  totalDetails: number;
}

export interface TaskView extends Task {
  subtasks: TaskSubtaskView[];
  progress: number;
  completedSubtasks: number;
  totalSubtasks: number;
  completedDetails: number;
  totalDetails: number;
  // NUOVI CAMPI
  assignedRoles: StaffRole[];
  assignedUsers: { id: string; firstName: string; lastName: string; }[];
}

// ─── Label maps ───────────────────────────────────────────────────────────────

export const ROLE_LABELS: Record<string, string> = {
  tutti:          'Tutti',
  manager:        'Responsabile',
  chef:           'Chef',
  waiter:         'Cameriere',
  kitchen_staff:  'Dipendente Cucina',
};

export const STATUS_LABELS: Record<TaskStatus, string> = {
  da_iniziare:   'Da Iniziare',
  in_lavorazione: 'In Lavorazione',
  completata:    'Completata',
};

export const PRIORITY_LABELS: Record<number, string> = {
  1: 'Minima',
  2: 'Bassa',
  3: 'Media',
  4: 'Alta',
  5: 'Urgente',
};

export interface TaskRoleAssignment {
  id: string;
  task_id: string;
  role: StaffRole;  // i ruoli dello staff (manager, chef, waiter, kitchen_staff)
  restaurant_id: string;
  created_at: string;
}

export interface TaskUserAssignment {
  id: string;
  task_id: string;
  user_id: string;
  restaurant_id: string;
  created_at: string;
}

// Per la visualizzazione nello staff
export interface StaffUser {
  id: string;
  user_id: string;
  first_name: string;
  last_name: string;
  email: string;
  role: StaffRole;
}

// Aggiorna TaskView (aggiungi campi per le assegnazioni)
export interface TaskView extends Task {
  subtasks: TaskSubtaskView[];
  progress: number;
  completedSubtasks: number;
  totalSubtasks: number;
  completedDetails: number;
  totalDetails: number;
  // Nuovi campi per assegnazioni multiple
  assignedRoles: StaffRole[];          // ruoli assegnati (dalla tabella task_role_assignments)
  assignedUsers: { id: string; firstName: string; lastName: string; }[];  // utenti specifici
}
